``` javascript
const workbook = new ExcelJS.Workbook()
const worksheet = workbook.getWorkSheet(1)

const merges = worksheet.model.merges

const mergesObj = merges.reduce((pre, cur) => {
  const [startAddr, endAddr] = cur.split(':')
  const startCell = worksheet.getCell(startAddr)
  const endCell = worksheet.getCell(endAddr)
  pre[startAddr] = {
    top: startCell.row,
    bottom: endCell.row,
    left: startCell.col,
    right: endCell.col,
    sheetName: startCell.sheetName
  }
  return pre
}, {})

console.log(mergesObj)
```
